import math

def uzaklık(p1, p2):
  return math.sqrt((p1[0] - p2[0])**2 + (p1[1] - p2[1])**2)

def brute_force(noktalar):
  min_uzaklık = float('inf')
  n = len(noktalar)
  if n <= 1:
    return min_uzaklık, None, None

  p1_son = None
  p2_son = None

  for i in range(n):
    for j in range(i+1, n):
      mesafe = uzaklık(noktalar[i], noktalar[j])
      if mesafe < min_uzaklık:
        min_uzaklık = mesafe
        p1_son = noktalar[i]
        p2_son = noktalar[j]
  return min_uzaklık, p1_son, p2_son

def şerit_minimum(noktalar, orta_x, d):
  şerit = []
  for nokta in noktalar:
    if abs(nokta[0] - orta_x) < d:
      şerit.append(nokta)

  şerit.sort(key=lambda nokta: nokta[1])

  min_uzaklık = d
  p1_son = None
  p2_son = None

  boyut = len(şerit)
  for i in range(boyut):
    j = i + 1
    while j < boyut and (şerit[j][1] - şerit[i][1]) < d:
      mesafe = uzaklık(şerit[i], şerit[j])
      if mesafe < min_uzaklık:
        min_uzaklık = mesafe
        p1_son = şerit[i]
        p2_son = şerit[j]
      j += 1
  return min_uzaklık, p1_son, p2_son


def en_yakın_çift(noktalar_x, noktalar_y):
  n = len(noktalar_x)
  if n <= 3:
    return brute_force(noktalar_x)

  orta = n // 2
  orta_x = noktalar_x[orta][0]

  noktalar_x_sol = noktalar_x[:orta]
  noktalar_x_sağ = noktalar_x[orta:]

  noktalar_y_sol = []
  noktalar_y_sağ = []

  for nokta in noktalar_y:
    if nokta[0] <= orta_x:
      noktalar_y_sol.append(nokta)
    else:
      noktalar_y_sağ.append(nokta)

  d_sol, p1_sol, p2_sol = en_yakın_çift(noktalar_x_sol, noktalar_y_sol)
  d_sağ, p1_sağ, p2_sağ = en_yakın_çift(noktalar_x_sağ, noktalar_y_sağ)

  if d_sol < d_sağ:
    d = d_sol
    p1 = p1_sol
    p2 = p2_sol
  else:
    d = d_sağ
    p1 = p1_sağ
    p2 = p2_sağ

  d_şerit, p1_şerit, p2_şerit = şerit_minimum(noktalar_y, orta_x, d)

  if d_şerit < d:
    return d_şerit, p1_şerit, p2_şerit
  else:
    return d, p1, p2


def en_yakın_çift_noktalar(noktalar):
    noktalar_x = sorted(noktalar, key=lambda nokta: nokta[0])
    noktalar_y = sorted(noktalar, key=lambda nokta: nokta[1])
    return en_yakın_çift(noktalar_x, noktalar_y)

if __name__ == '__main__':
  noktalar = [(2, 3), (12, 30), (40, 50), (5, 1), (12, 10), (3, 4)]
  min_uzaklık, p1, p2 = en_yakın_çift_noktalar(noktalar)
  print("En yakın uzaklık:", min_uzaklık)
  print("Nokta 1:", p1)
  print("Nokta 2:", p2)

